-- heratio#1231 - Research OS #9: Method Design Studio - discipline templates.
--
-- INSERT IGNORE keyed on the unique `code`, so re-running is idempotent and a
-- site that has hand-edited a template keeps its edits. The `guidance` column
-- is a JSON object: an ordered map of area-key => {label, prompt, placeholder}.
--
-- Guidance is intentionally JURISDICTION-NEUTRAL. Ethics / consent / data-
-- management prompts speak to general principles (informed consent, lawful
-- basis, retention, anonymisation) and never name a specific country's regime.
-- A site layers its own market module (GDPR, POPIA, IPSAS, etc.) on top.

INSERT IGNORE INTO `research_method_template`
  (`code`, `name`, `discipline`, `description`, `guidance`, `is_active`, `sort_order`, `created_at`, `updated_at`)
VALUES
('design-science', 'Design Science Research', 'Information Systems / Engineering',
 'Build-and-evaluate of an artefact (model, method, instantiation) against defined objectives, with rigorous demonstration and evaluation cycles.',
 '{"design":{"label":"Research design","prompt":"State the artefact you will build and the design-science cycle (problem identification, objectives, design, demonstration, evaluation, communication) you will follow.","placeholder":"e.g. We design a method artefact and evaluate it over two build-evaluate iterations."},"sampling":{"label":"Cases / evaluation settings","prompt":"Which cases, datasets, or settings will the artefact be demonstrated and evaluated in, and why are they representative?","placeholder":""},"data_sources":{"label":"Data sources","prompt":"What evidence feeds the design and the evaluation (logs, expert input, benchmark datasets)?","placeholder":""},"instruments":{"label":"Evaluation instruments","prompt":"How will the artefact be measured (metrics, expert criteria, technical benchmarks)?","placeholder":""},"coding_framework":{"label":"Analysis framework","prompt":"How will qualitative evaluation feedback be structured or coded, if any?","placeholder":""},"variables":{"label":"Constructs / variables","prompt":"List the design constructs and the evaluation criteria they map to.","placeholder":""},"validity":{"label":"Validity","prompt":"How do you establish that the artefact actually solves the stated problem (construct, internal, external validity)?","placeholder":""},"reliability":{"label":"Rigour / reliability","prompt":"How is the build-evaluate process documented so it can be inspected and repeated?","placeholder":""},"ethics":{"label":"Ethics","prompt":"Identify any human or organisational involvement and the ethical review obtained.","placeholder":""},"consent":{"label":"Consent","prompt":"How is informed consent obtained from any experts or participants involved in evaluation?","placeholder":""},"bias_control":{"label":"Bias control","prompt":"How do you guard against designer bias in evaluating your own artefact?","placeholder":""},"reproducibility":{"label":"Reproducibility","prompt":"How will the artefact, its inputs, and its evaluation be packaged so others can reproduce the result?","placeholder":""},"data_management":{"label":"Data management","prompt":"Where are artefacts, datasets, and evaluation records stored, with what retention and access controls?","placeholder":""}}',
 1, 10, NOW(), NOW()),

('archival-method', 'Archival / Documentary Method', 'Archival Science / History',
 'Systematic interrogation of records and finding aids: provenance, original order, diplomatics, and source criticism of archival documents.',
 '{"design":{"label":"Research design","prompt":"Describe your archival approach: which fonds/collections, what arrangement you respect (provenance, original order), and your reading strategy.","placeholder":""},"sampling":{"label":"Record selection","prompt":"How do you select records and series from the corpus? State inclusion / exclusion criteria.","placeholder":""},"data_sources":{"label":"Sources","prompt":"List archives, repositories, and record groups consulted, with their custodial context.","placeholder":""},"instruments":{"label":"Reading / transcription instruments","prompt":"What tools or templates structure your transcription, calendaring, or item-level notes?","placeholder":""},"coding_framework":{"label":"Coding / indexing framework","prompt":"How will you index or thematically code the records (subjects, actors, events)?","placeholder":""},"variables":{"label":"Analytical dimensions","prompt":"Which dimensions do you track across records (date, creator, document type, authenticity)?","placeholder":""},"validity":{"label":"Source criticism / validity","prompt":"How do you assess authenticity, reliability, and integrity of each record (diplomatics, external/internal criticism)?","placeholder":""},"reliability":{"label":"Reliability","prompt":"How are transcriptions and interpretations checked for consistency?","placeholder":""},"ethics":{"label":"Ethics","prompt":"Address access restrictions, third-party privacy in records, and any sensitivity of the material.","placeholder":""},"consent":{"label":"Consent / permissions","prompt":"What permissions are needed from custodians or rights holders to use and reproduce records?","placeholder":""},"bias_control":{"label":"Bias control","prompt":"How do you account for gaps and silences in the archive and the bias of what was kept?","placeholder":""},"reproducibility":{"label":"Reproducibility / citation","prompt":"How are records cited (reference codes, repository) so another scholar can locate the same item?","placeholder":""},"data_management":{"label":"Data management","prompt":"How are surrogates, transcriptions, and notes stored, with what retention and rights handling?","placeholder":""}}',
 1, 20, NOW(), NOW()),

('ethnography', 'Ethnography', 'Anthropology / Sociology',
 'Immersive fieldwork producing thick description of a community or setting through participant observation and field notes.',
 '{"design":{"label":"Research design","prompt":"Describe the field site, your role (participant / observer), and the duration and rhythm of fieldwork.","placeholder":""},"sampling":{"label":"Site & participant selection","prompt":"How are the setting and informants chosen (purposive, snowball)? Who is included?","placeholder":""},"data_sources":{"label":"Data sources","prompt":"What data will you gather (field notes, informal interviews, artefacts, photos)?","placeholder":""},"instruments":{"label":"Instruments","prompt":"What field-note protocol, interview guides, or observation grids will you use?","placeholder":""},"coding_framework":{"label":"Coding framework","prompt":"How will field notes be coded (open / axial, thematic categories)?","placeholder":""},"variables":{"label":"Sensitising concepts","prompt":"Which concepts or themes orient your observation without over-determining it?","placeholder":""},"validity":{"label":"Trustworthiness","prompt":"How do you establish credibility (prolonged engagement, triangulation, member checking)?","placeholder":""},"reliability":{"label":"Dependability","prompt":"How is the inquiry audit-trailed so the process is dependable?","placeholder":""},"ethics":{"label":"Ethics","prompt":"Address the power relationship, potential harm, anonymity of the community, and ethical review.","placeholder":""},"consent":{"label":"Consent","prompt":"How is informed, ongoing consent obtained in a setting where consent is processual?","placeholder":""},"bias_control":{"label":"Reflexivity / bias control","prompt":"How do you reflexively account for your own positionality and its effect on the field?","placeholder":""},"reproducibility":{"label":"Transferability","prompt":"What contextual detail lets readers judge transferability to other settings?","placeholder":""},"data_management":{"label":"Data management","prompt":"How are field notes and recordings secured, anonymised, retained, and eventually disposed of?","placeholder":""}}',
 1, 30, NOW(), NOW()),

('case-study', 'Case Study', 'Social Science / Management',
