 '{"design":{"label":"Research design","prompt":"Describe the qualitative approach and its philosophical stance (interpretivist, constructivist).","placeholder":""},"sampling":{"label":"Sampling","prompt":"State the sampling strategy and how you judge sufficiency (saturation, information power).","placeholder":""},"data_sources":{"label":"Data sources","prompt":"What qualitative data will you collect (interviews, focus groups, documents)?","placeholder":""},"instruments":{"label":"Instruments","prompt":"Describe interview / focus-group guides and how they were developed and piloted.","placeholder":""},"coding_framework":{"label":"Coding framework","prompt":"What coding and theme-development method will you use (thematic analysis, framework, grounded theory)?","placeholder":""},"variables":{"label":"Concepts","prompt":"What initial concepts or topics orient analysis?","placeholder":""},"validity":{"label":"Trustworthiness","prompt":"How do you ensure credibility, transferability, dependability, confirmability?","placeholder":""},"reliability":{"label":"Coding consistency","prompt":"How is coding consistency handled (codebook, inter-coder agreement)?","placeholder":""},"ethics":{"label":"Ethics","prompt":"Address potential harm, confidentiality, and ethical review.","placeholder":""},"consent":{"label":"Consent","prompt":"How is informed consent obtained and documented?","placeholder":""},"bias_control":{"label":"Reflexivity / bias control","prompt":"How is researcher influence acknowledged and managed?","placeholder":""},"reproducibility":{"label":"Auditability","prompt":"How is the analytic trail recorded so the route from data to findings is transparent?","placeholder":""},"data_management":{"label":"Data management","prompt":"How are recordings, transcripts, and codes stored, anonymised, and retained?","placeholder":""}}',
