('quantitative', 'Quantitative (General)', 'General',
 'Measurement-based approach testing hypotheses with statistical analysis of numeric data.',
 '{"design":{"label":"Research design","prompt":"State the design (experimental, quasi-experimental, survey, correlational) and rationale.","placeholder":""},"sampling":{"label":"Sampling","prompt":"Define population, sampling frame, technique, and target sample size with power justification.","placeholder":""},"data_sources":{"label":"Data sources","prompt":"What numeric data will you collect or obtain, and from where?","placeholder":""},"instruments":{"label":"Instruments","prompt":"Describe measurement instruments, their scales, and prior validation.","placeholder":""},"coding_framework":{"label":"Data coding","prompt":"How are responses coded and cleaned for analysis?","placeholder":""},"variables":{"label":"Variables","prompt":"List independent, dependent, control, and confounding variables with operational definitions.","placeholder":""},"validity":{"label":"Validity","prompt":"Address measurement validity and internal / external validity of the design.","placeholder":""},"reliability":{"label":"Reliability","prompt":"State reliability evidence (Cronbach alpha, test-retest) for the instruments.","placeholder":""},"ethics":{"label":"Ethics","prompt":"Address participant risk, confidentiality, and ethical clearance.","placeholder":""},"consent":{"label":"Consent","prompt":"How is informed consent obtained for data collection?","placeholder":""},"bias_control":{"label":"Bias control","prompt":"How do you control selection, response, and analysis bias (randomisation, blinding, pre-registration)?","placeholder":""},"reproducibility":{"label":"Reproducibility","prompt":"How will data and analysis code be shared so results can be reproduced?","placeholder":""},"data_management":{"label":"Data management","prompt":"Where are the dataset and analysis files stored, with what retention and access controls?","placeholder":""}}',
