('mixed-methods', 'Mixed Methods', 'General',
 'Combines quantitative and qualitative strands with an explicit integration design (convergent, explanatory, exploratory).',
 '{"design":{"label":"Research design","prompt":"State the mixed-methods design (convergent, explanatory sequential, exploratory sequential) and the point of integration.","placeholder":""},"sampling":{"label":"Sampling","prompt":"Describe sampling for each strand and how the samples relate (nested, parallel).","placeholder":""},"data_sources":{"label":"Data sources","prompt":"List both quantitative and qualitative data sources.","placeholder":""},"instruments":{"label":"Instruments","prompt":"Describe instruments for each strand and any that bridge the two.","placeholder":""},"coding_framework":{"label":"Analysis framework","prompt":"How are the strands analysed and then integrated (joint display, data transformation)?","placeholder":""},"variables":{"label":"Constructs / variables","prompt":"List the variables and qualitative concepts and where they meet.","placeholder":""},"validity":{"label":"Validity / legitimation","prompt":"Address validity for each strand and the legitimation of the integrated inference.","placeholder":""},"reliability":{"label":"Reliability","prompt":"How is rigour maintained in both strands?","placeholder":""},"ethics":{"label":"Ethics","prompt":"Address ethical considerations spanning both strands.","placeholder":""},"consent":{"label":"Consent","prompt":"How is consent handled where participants contribute to more than one strand?","placeholder":""},"bias_control":{"label":"Bias control","prompt":"How is bias controlled in each strand and at integration?","placeholder":""},"reproducibility":{"label":"Reproducibility","prompt":"How are both datasets and the integration procedure documented for reuse?","placeholder":""},"data_management":{"label":"Data management","prompt":"How are the combined data assets stored, linked, and retained securely?","placeholder":""}}',
 1, 70, NOW(), NOW()),

('discourse-analysis', 'Discourse Analysis', 'Linguistics / Media Studies',
 'Close analysis of how language constructs meaning, identity, and power across a corpus of texts or talk.',
 '{"design":{"label":"Research design","prompt":"State the discourse-analytic approach (critical discourse analysis, conversation analysis, corpus-assisted) and unit of analysis.","placeholder":""},"sampling":{"label":"Corpus selection","prompt":"How is the text / talk corpus assembled and bounded?","placeholder":""},"data_sources":{"label":"Data sources","prompt":"What texts, transcripts, or media make up the corpus, and where are they from?","placeholder":""},"instruments":{"label":"Analytic instruments","prompt":"What transcription conventions or analytic categories will you apply?","placeholder":""},"coding_framework":{"label":"Coding framework","prompt":"What linguistic / rhetorical features and discursive strategies will you code?","placeholder":""},"variables":{"label":"Analytic dimensions","prompt":"Which discursive dimensions (modality, agency, framing) do you track?","placeholder":""},"validity":{"label":"Validity","prompt":"How is interpretive validity established (close reading, deviant cases, intertextual grounding)?","placeholder":""},"reliability":{"label":"Consistency","prompt":"How is analytic consistency handled across the corpus?","placeholder":""},"ethics":{"label":"Ethics","prompt":"Address the status of the texts (public vs private), authorship, and any privacy concerns.","placeholder":""},"consent":{"label":"Consent","prompt":"Where talk is recorded from participants, how is consent obtained?","placeholder":""},"bias_control":{"label":"Bias control","prompt":"How do you guard against cherry-picking and confirm your reading against the full corpus?","placeholder":""},"reproducibility":{"label":"Reproducibility","prompt":"How is the corpus and coding scheme documented so another analyst could follow it?","placeholder":""},"data_management":{"label":"Data management","prompt":"How is the corpus stored and rights-cleared, with what retention?","placeholder":""}}',
 1, 80, NOW(), NOW()),

('historical-method', 'Historical Method', 'History',
 'Reconstruction and interpretation of the past through critical evaluation of primary and secondary sources.',
 '{"design":{"label":"Research design","prompt":"State the historical question, period, and the interpretive frame (narrative, comparative, microhistory).","placeholder":""},"sampling":{"label":"Source selection","prompt":"How do you select sources across archives and how do you handle gaps?","placeholder":""},"data_sources":{"label":"Sources","prompt":"List primary and secondary sources and their provenance.","placeholder":""},"instruments":{"label":"Note / extract instruments","prompt":"What note-taking, calendaring, or extraction templates structure your reading?","placeholder":""},"coding_framework":{"label":"Thematic framework","prompt":"How do you organise evidence thematically or chronologically?","placeholder":""},"variables":{"label":"Analytical threads","prompt":"Which actors, events, and causal threads do you trace?","placeholder":""},"validity":{"label":"Source criticism","prompt":"How do you apply external and internal source criticism to establish authenticity and reliability?","placeholder":""},"reliability":{"label":"Corroboration","prompt":"How do you corroborate claims across independent sources?","placeholder":""},"ethics":{"label":"Ethics","prompt":"Address living subjects, sensitive histories, and any access restrictions.","placeholder":""},"consent":{"label":"Permissions","prompt":"What permissions are needed to consult and reproduce restricted sources?","placeholder":""},"bias_control":{"label":"Bias control","prompt":"How do you account for the bias of surviving sources and your own interpretive standpoint?","placeholder":""},"reproducibility":{"label":"Citation / verifiability","prompt":"How are sources cited so claims can be verified at the original?","placeholder":""},"data_management":{"label":"Data management","prompt":"How are surrogates, transcriptions, and research notes stored and retained?","placeholder":""}}',
