('legal-policy', 'Legal / Policy Analysis', 'Law / Public Policy',
 'Doctrinal and policy analysis of legal instruments, case law, and regulatory frameworks. Treat the legal corpus as jurisdiction-neutral; name the jurisdiction in your answers, not in the template.',
 '{"design":{"label":"Research design","prompt":"State whether the analysis is doctrinal, comparative, or socio-legal, and the jurisdiction(s) in scope.","placeholder":""},"sampling":{"label":"Source / jurisdiction selection","prompt":"Which instruments, cases, and jurisdictions are in scope and why?","placeholder":""},"data_sources":{"label":"Legal sources","prompt":"List statutes, regulations, case law, treaties, and policy documents consulted.","placeholder":""},"instruments":{"label":"Analytic instruments","prompt":"What framework structures the analysis (issue-rule-application-conclusion, comparative matrix)?","placeholder":""},"coding_framework":{"label":"Coding framework","prompt":"How will provisions and holdings be categorised and compared?","placeholder":""},"variables":{"label":"Analytical dimensions","prompt":"Which legal dimensions (scope, obligations, remedies, sanctions) do you compare?","placeholder":""},"validity":{"label":"Validity / authority","prompt":"How do you ensure you rely on authoritative, current sources of law?","placeholder":""},"reliability":{"label":"Reliability","prompt":"How do you verify the currency and accuracy of cited provisions?","placeholder":""},"ethics":{"label":"Ethics","prompt":"Address any empirical component involving people and the ethical clearance required.","placeholder":""},"consent":{"label":"Consent","prompt":"If interviews with practitioners are used, how is consent handled?","placeholder":""},"bias_control":{"label":"Bias control","prompt":"How do you present competing interpretations fairly rather than selectively?","placeholder":""},"reproducibility":{"label":"Reproducibility","prompt":"How are citations to law given so the reader can locate the exact provision?","placeholder":""},"data_management":{"label":"Data management","prompt":"How are collected legal materials and any empirical data stored and retained?","placeholder":""}}',
 1, 100, NOW(), NOW()),

('computational-dh', 'Computational / Digital Humanities', 'Digital Humanities',
 'Computational treatment of cultural data: text mining, network analysis, mapping, and modelling over digitised corpora.',
 '{"design":{"label":"Research design","prompt":"State the computational approach (text mining, network analysis, topic modelling, GIS) and how it answers the humanities question.","placeholder":""},"sampling":{"label":"Corpus construction","prompt":"How is the corpus built, cleaned, and bounded? What is included or excluded?","placeholder":""},"data_sources":{"label":"Data sources","prompt":"What digitised collections, datasets, or APIs feed the analysis?","placeholder":""},"instruments":{"label":"Tools / pipeline","prompt":"What software, libraries, and pipeline steps will you use?","placeholder":""},"coding_framework":{"label":"Annotation / coding","prompt":"How is the corpus annotated, tagged, or feature-engineered?","placeholder":""},"variables":{"label":"Features / parameters","prompt":"List the features, metrics, and model parameters you analyse.","placeholder":""},"validity":{"label":"Validity","prompt":"How do you validate computational results against close reading or ground truth?","placeholder":""},"reliability":{"label":"Reliability","prompt":"How stable are results to parameter and pre-processing choices?","placeholder":""},"ethics":{"label":"Ethics","prompt":"Address rights in the corpus, sensitive content, and any algorithmic harm.","placeholder":""},"consent":{"label":"Consent / rights","prompt":"What licensing or consent governs reuse of the source data?","placeholder":""},"bias_control":{"label":"Bias control","prompt":"How do you surface and account for bias in data, tools, and models? If a model assists analysis it must run through the institutional AI gateway, never a direct node.","placeholder":""},"reproducibility":{"label":"Reproducibility","prompt":"How will code, parameters, and environment be shared so the analysis can be re-run?","placeholder":""},"data_management":{"label":"Data management","prompt":"Where are the corpus, derived datasets, and code archived, with what versioning and retention?","placeholder":""}}',
 1, 110, NOW(), NOW());

